PROGRAM TankLevelMonitor
VAR_INPUT
    RawLevel : INT;
    HighAlarmSP : REAL := 85.0;
    LowAlarmSP : REAL := 15.0;
    Hysteresis : REAL := 2.0;
END_VAR

VAR_OUTPUT
    LevelPct : REAL;
    HighAlarm : BOOL;
    LowAlarm : BOOL;
END_VAR

VAR
    HighAlarmState : BOOL := FALSE;
    LowAlarmState : BOOL := FALSE;
END_VAR

// Пересчет сырого значения в проценты
LevelPct := REAL(RawLevel) / 276.48;

// Логика HighAlarm с гистерезисом
// Включить при LevelPct >= HighAlarmSP
// Выключить при LevelPct < HighAlarmSP - Hysteresis
IF LevelPct >= HighAlarmSP THEN
    HighAlarmState := TRUE;
ELSIF LevelPct < (HighAlarmSP - Hysteresis) THEN
    HighAlarmState := FALSE;
END_IF;
HighAlarm := HighAlarmState;

// Логика LowAlarm с гистерезисом
// Включить при LevelPct <= LowAlarmSP
// Выключить при LevelPct > LowAlarmSP + Hysteresis
IF LevelPct <= LowAlarmSP THEN
    LowAlarmState := TRUE;
ELSIF LevelPct > (LowAlarmSP + Hysteresis) THEN
    LowAlarmState := FALSE;
END_IF;
LowAlarm := LowAlarmState;
END_PROGRAM

PROGRAM MotorStarDelta
VAR_INPUT
    Start_btn : BOOL;
    Stop_btn : BOOL;
    Overload : BOOL;
END_VAR

VAR_OUTPUT
    Main_Contactor : BOOL;
    Star_Contactor : BOOL;
    Delta_Contactor : BOOL;
    Fault : BOOL;
END_VAR

VAR
    MotorRunning : BOOL := FALSE;
    StartTrig : R_TRIG;
    StartEdge : BOOL;
    TimerStarDelta : TON;
END_VAR

StartTrig(CLK := Start_btn);
StartEdge := StartTrig.Q;

IF NOT Stop_btn AND NOT Overload THEN
    IF StartEdge THEN
        MotorRunning := TRUE;
    END_IF;

    IF MotorRunning THEN
        Main_Contactor := TRUE;
        Star_Contactor := TRUE;
        Delta_Contactor := FALSE;
        TimerStarDelta(IN := TRUE, PT := T#3S);

        IF TimerStarDelta.Q THEN
            Star_Contactor := FALSE;
            Delta_Contactor := TRUE;
        END_IF;
        Fault := FALSE;
    END_IF;
ELSE
    MotorRunning := FALSE;
    Main_Contactor := FALSE;
    Star_Contactor := FALSE;
    Delta_Contactor := FALSE;
    TimerStarDelta(IN := FALSE);
    Fault := Overload;
END_IF;
END_PROGRAM

TYPE ConveyorState : (ST_IDLE, ST_RUNNING, ST_REJECTING, ST_FAULT); END_TYPE

PROGRAM SortingConveyor
VAR_INPUT
    StartCmd : BOOL;
    SensorPresent : BOOL;
    SensorDefect : BOOL;
    EStop : BOOL;
END_VAR

VAR_OUTPUT
    MotorRun : BOOL;
    RejectSolenoid : BOOL;
END_VAR

VAR
    State : ConveyorState := ST_IDLE;
    RejectTimer : TON;
END_VAR

// Обработка аварийной остановки
IF EStop THEN
    State := ST_FAULT;
    RejectTimer(IN := FALSE);
ELSIF State = ST_FAULT THEN
    // Выход из FAULT когда EStop снят
    State := ST_IDLE;
ELSE
    // Логика состояний
    CASE State OF
        ST_IDLE:
            IF StartCmd THEN
                State := ST_RUNNING;
            END_IF;

        ST_RUNNING:
            IF SensorPresent AND SensorDefect THEN
                State := ST_REJECTING;
                RejectTimer(IN := TRUE, PT := T#500ms);
            ELSE
                RejectTimer(IN := FALSE);
            END_IF;

        ST_REJECTING:
            IF RejectTimer.Q THEN
                State := ST_RUNNING;
                RejectTimer(IN := FALSE);
            ELSE
                RejectTimer(IN := TRUE);
            END_IF;
    END_CASE;
END_IF;

// Выходы
MotorRun := (State = ST_RUNNING);
RejectSolenoid := (State = ST_REJECTING);

END_PROGRAM

FUNCTION_BLOCK PID_Temperature
VAR_INPUT
    Enable : BOOL;
    Setpoint : REAL;
    ProcessValue : REAL;
    Kp : REAL := 2.0;
    Ki : REAL := 0.05;
    Kd : REAL := 0.0;
    CycleTime : TIME := T#100ms;
END_VAR
VAR_OUTPUT
    Output : REAL;
END_VAR
VAR
    Integral : REAL := 0.0;
    LastError : REAL := 0.0;
    Ts : REAL;
    Error : REAL;
END_VAR

Ts := TIME_TO_REAL(CycleTime);
IF NOT Enable THEN
    Output := 0.0;
    Integral := 0.0;
    LastError := 0.0;
ELSE
    Error := Setpoint - ProcessValue;
    Integral := Integral + Error * Ts;
    IF Ts > 0.0 THEN
        Output := Kp * Error + Ki * Integral + Kd * (Error - LastError) / Ts;
    ELSE
        Output := Kp * Error + Ki * Integral;
    END_IF;
    LastError := Error;
    IF Output < 0.0 THEN
        Output := 0.0;
    ELSIF Output > 100.0 THEN
        Output := 100.0;
    END_IF;
END_IF;
END_FUNCTION_BLOCK

PROGRAM PumpLeadLag
VAR_INPUT
    LevelLow : BOOL;
    LevelHigh : BOOL;
    Pump1Fault : BOOL;
    Pump2Fault : BOOL;
    ManualMode : BOOL;
    ManualP1Run : BOOL;
    ManualP2Run : BOOL;
END_VAR
VAR_OUTPUT
    P1Run : BOOL;
    P2Run : BOOL;
END_VAR
VAR
    LeadPump : INT := 1;
END_VAR

IF ManualMode THEN
    P1Run := ManualP1Run;
    P2Run := ManualP2Run;
ELSE
    IF LevelHigh THEN
        P1Run := FALSE;
        P2Run := FALSE;
    ELSIF LevelLow THEN
        IF Pump1Fault AND Pump2Fault THEN
            P1Run := FALSE;
            P2Run := FALSE;
        ELSIF Pump1Fault THEN
            LeadPump := 2;
        ELSIF Pump2Fault THEN
            LeadPump := 1;
        END_IF;

        IF LeadPump = 1 THEN
            P1Run := TRUE;
            P2Run := FALSE;
        ELSE
            P1Run := FALSE;
            P2Run := TRUE;
        END_IF;
    ELSE
        P1Run := FALSE;
        P2Run := FALSE;
    END_IF;
END_IF;
END_PROGRAM

PROGRAM BatchDoseSequence
VAR_INPUT
    StartSeq : BOOL;
    Abort    : BOOL;
END_VAR

VAR_OUTPUT
    Valve1   : BOOL;
    Valve2   : BOOL;
    Valve3   : BOOL;
    SeqDone  : BOOL;
    SeqActive: BOOL;
END_VAR

VAR
    Step : INT := 0;
    T1   : TON;
    T2   : TON;
    T3   : TON;
END_VAR

IF Abort THEN
    Step := 0;
    Valve1 := FALSE;
    Valve2 := FALSE;
    Valve3 := FALSE;
    SeqDone := FALSE;
    SeqActive := FALSE;
    T1(IN := FALSE);
    T2(IN := FALSE);
    T3(IN := FALSE);
ELSE
    CASE Step OF
        0:
            SeqActive := FALSE;
            SeqDone := FALSE;
            IF StartSeq THEN
                Step := 1;
            END_IF;

        1:
            Valve1 := TRUE;
            Valve2 := FALSE;
            Valve3 := FALSE;
            SeqActive := TRUE;
            T1(IN := TRUE, PT := T#2s);
            IF T1.Q THEN
                Step := 2;
            END_IF;

        2:
            Valve1 := TRUE;
            Valve2 := TRUE;
            Valve3 := FALSE;
            SeqActive := TRUE;
            T2(IN := TRUE, PT := T#3s);
            IF T2.Q THEN
                Step := 3;
            END_IF;

        3:
            Valve1 := TRUE;
            Valve2 := TRUE;
            Valve3 := TRUE;
            SeqActive := TRUE;
            T3(IN := TRUE, PT := T#1s);
            IF T3.Q THEN
                Step := 4;
            END_IF;

        4:
            Valve1 := FALSE;
            Valve2 := FALSE;
            Valve3 := FALSE;
            SeqActive := FALSE;
            SeqDone := TRUE;
            T1(IN := FALSE);
            T2(IN := FALSE);
            T3(IN := FALSE);
    END_CASE;
END_IF;
END_PROGRAM

PROGRAM SafetyInterlock
VAR_INPUT
    EStopOK     : BOOL;
    GuardClosed : BOOL;
    ResetPB     : BOOL;
END_VAR
VAR_OUTPUT
    MachineEnable : BOOL;
    SafetyFault   : BOOL;
END_VAR
VAR
    ResetTrig : R_TRIG;
END_VAR

ResetTrig(CLK := ResetPB);

IF NOT EStopOK OR NOT GuardClosed THEN
    SafetyFault := TRUE;
ELSIF ResetTrig.Q AND EStopOK AND GuardClosed THEN
    SafetyFault := FALSE;
END_IF;

MachineEnable := NOT SafetyFault AND EStopOK AND GuardClosed;
END_PROGRAM

PROGRAM ProductionCounter
VAR_INPUT
    ProductSensor : BOOL;
    ResetBatch    : BOOL;
    BatchTarget   : INT := 1000;
END_VAR
VAR_OUTPUT
    BatchCount    : INT;
    BatchComplete : BOOL;
    TotalCount    : INT;
END_VAR
VAR
    SensorTrig : R_TRIG;
    Counter    : CTU;
END_VAR

SensorTrig(CLK := ProductSensor);
Counter(CU := SensorTrig.Q, R := ResetBatch, PV := BatchTarget);

BatchCount := Counter.CV;
BatchComplete := Counter.Q;
IF SensorTrig.Q THEN
    TotalCount := TotalCount + 1;
END_IF;
END_PROGRAM

FUNCTION_BLOCK MovingAverageFilter
VAR_INPUT
    Enable : BOOL;
    RawInput : REAL;
    WindowSize : INT;
END_VAR
VAR_OUTPUT
    Filtered : REAL;
END_VAR
VAR
    Buffer : ARRAY[0..9] OF REAL;
    Head : INT;
    Count : INT;
    Sum : REAL;
    EffectiveSize : INT;
END_VAR

IF NOT Enable THEN
    Head := 0;
    Count := 0;
    Sum := 0.0;
    Filtered := 0.0;
ELSE
    IF WindowSize < 1 THEN
        EffectiveSize := 1;
    ELSIF WindowSize > 10 THEN
        EffectiveSize := 10;
    ELSE
        EffectiveSize := WindowSize;
    END_IF;

    IF Count < EffectiveSize THEN
        Sum := Sum + RawInput;
        Count := Count + 1;
    ELSE
        Sum := Sum - Buffer[Head] + RawInput;
    END_IF;

    Buffer[Head] := RawInput;
    Head := (Head + 1) MOD 10;

    IF Count > 0 THEN
        Filtered := Sum / INT_TO_REAL(Count);
    ELSE
        Filtered := 0.0;
    END_IF;
END_IF;
END_FUNCTION_BLOCK
